const icon = (
  className: string,
  paths: ReadonlyArray<string>,
  attributes: ReadonlyArray<Attribute<never>> = [],
): Html => {
  const h = html<never>()

  return h.svg(
    [
      h.Xmlns('http://www.w3.org/2000/svg'),
      h.Width('24'),
      h.Height('24'),
      h.ViewBox('0 0 24 24'),
      h.Fill('none'),
      h.Stroke('currentColor'),
      h.StrokeWidth('2'),
      h.StrokeLinecap('round'),
      h.StrokeLinejoin('round'),
      h.AriaHidden(true),
      h.Class(className),
      ...attributes,
    ],
    paths.map(path => h.path([h.D(path)], [])),
  )
}

